import java.util.*; public class Rook extends Piece { public Rook(PieceColor color){super(color);} @Override public char getSymbol(){return 'r';} @Override public List<Move> getLegalMoves(Position from, Board board){ List<Move> res=new ArrayList<>(); int[][] dirs={{1,0},{-1,0},{0,1},{0,-1}}; for(int[] d:dirs){ int r=from.row, c=from.col; while(true){ r+=d[0]; c+=d[1]; if(!inBounds(r,c)) break; Position to=new Position(r,c); Piece t=board.getPiece(to); if(t==null) res.add(new Move(from,to,this,null)); else{ if(t.getColor()!=color) res.add(new Move(from,to,this,t)); break; } } } return res; } @Override public Piece copy(){ Rook p=new Rook(color); p.moved=this.moved; return p; } }